-- ============================================================
-- Asignar chofer y colector a los 500 autobuses nuevos
-- (IDs autoincrementales: choferes empiezan desde 1, colectores desde 500 + 1)
-- En un entorno dev limpio, los IDs de choferes serán 1-500
-- y los de colectores serán 501-1000 (si es fresh start)
-- ============================================================

-- ============================================================
-- Asignar chofer_id y colector_id a los autobuses nuevos
-- Usa ROW_NUMBER() + CTE (MySQL 8.0+) para emparejar secuencialmente
-- el n-ésimo autobús nuevo con el n-ésimo chofer y n-ésimo colector
-- ============================================================

WITH autobuses_para_asignar AS (
    SELECT id, ROW_NUMBER() OVER (ORDER BY id) AS rn
    FROM autobuses
    WHERE ruta_id IS NOT NULL AND chofer_id IS NULL
),
choferes_ordenados AS (
    SELECT id, ROW_NUMBER() OVER (ORDER BY id) AS rn
    FROM choferes
)
UPDATE autobuses a
    JOIN autobuses_para_asignar aa ON a.id = aa.id
    JOIN choferes_ordenados co ON co.rn = aa.rn
    SET a.chofer_id = co.id;

WITH autobuses_para_asignar AS (
    SELECT id, ROW_NUMBER() OVER (ORDER BY id) AS rn
    FROM autobuses
    WHERE ruta_id IS NOT NULL AND colector_id IS NULL
),
colectores_ordenados AS (
    SELECT id, ROW_NUMBER() OVER (ORDER BY id) AS rn
    FROM colectores
)
UPDATE autobuses a
    JOIN autobuses_para_asignar aa ON a.id = aa.id
    JOIN colectores_ordenados co ON co.rn = aa.rn
    SET a.colector_id = co.id;

